/* Called on first boot after update to confirm firmware is working */
fw_err_t firmware_confirm_update(void)
{
    const esp_partition_t *running = esp_ota_get_running_partition();
    esp_ota_img_states_t ota_state;

    esp_err_t err = esp_ota_get_state_partition(running, &ota_state);
    if (err != ESP_OK) {
        ESP_LOGW(TAG, "Failed to get OTA state: %s", esp_err_to_name(err));
        return FW_OK; /* Not an OTA partition, nothing to confirm */
    }

    if (ota_state == ESP_OTA_IMG_PENDING_VERIFY) {
        ESP_LOGI(TAG, "Confirming new firmware as valid");
        err = esp_ota_mark_app_valid_cancel_rollback();
        if (err != ESP_OK) {
            ESP_LOGE(TAG, "Failed to confirm firmware: %s", esp_err_to_name(err));
            return FW_ERR_ROLLBACK;
        }
        ESP_LOGI(TAG, "Firmware confirmed successfully");
    }

    return FW_OK;
}

/* Rollback to previous firmware */
fw_err_t firmware_rollback(void)
{
    ESP_LOGW(TAG, "Rolling back to previous firmware");

    esp_err_t err = esp_ota_mark_app_invalid_rollback_and_reboot();
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Rollback failed: %s", esp_err_to_name(err));
        return FW_ERR_ROLLBACK;
    }

    /* Should not reach here - device reboots */
    return FW_OK;
}

/* Get current running firmware info */
void firmware_get_info(char *version_buf, uint32_t buf_len)
{
    if (!version_buf || buf_len == 0)
        return;

    const esp_app_desc_t *app_desc = esp_app_get_description();
    if (app_desc) {
        snprintf(version_buf, buf_len, "%s (built %s %s)",
                 app_desc->version, app_desc->date, app_desc->time);
    } else {
        snprintf(version_buf, buf_len, "unknown");
    }
}

/* Auto-rollback watchdog: if firmware_confirm_update() is not called
   within ROLLBACK_TIMEOUT_S seconds, automatically roll back */
static void rollback_timer_callback(void *arg)
{
    (void)arg;
    const esp_partition_t *running = esp_ota_get_running_partition();
    esp_ota_img_states_t ota_state;

    if (esp_ota_get_state_partition(running, &ota_state) == ESP_OK) {
        if (ota_state == ESP_OTA_IMG_PENDING_VERIFY) {
            ESP_LOGE(TAG, "Firmware not confirmed within timeout - rolling back!");
            firmware_rollback();
        }
    }
}

fw_err_t firmware_start_rollback_watchdog(void)
{
    esp_timer_handle_t timer;
    esp_timer_create_args_t timer_args = {
        .callback = rollback_timer_callback,
        .arg = NULL,
        .dispatch_method = ESP_TIMER_TASK,
        .name = "fw_rollback_wd"
    };

    esp_err_t err = esp_timer_create(&timer_args, &timer);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to create rollback timer");
        return FW_ERR_INVALID;
    }

    err = esp_timer_start_once(timer, (uint64_t)ROLLBACK_TIMEOUT_S * 1000000);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to start rollback timer");
        esp_timer_delete(timer);
        return FW_ERR_INVALID;
    }

    ESP_LOGI(TAG, "Rollback watchdog started (%d seconds)", ROLLBACK_TIMEOUT_S);
    return FW_OK;
}

